mapper.select:
SELECT cawc.*, cceat.long_ex, cceat.short_ex, cceat.symbol FROM coins_arbitrage_warning_config cawc LEFT JOIN coins_cross_exchange_arbitrage_task cceat ON cawc.task_id = cceat.id
AND cawc.arbitrage_type = #{warningConfig.arbitrageType}
AND cawc.user_id = #{warningConfig.userId}
AND cawc.config_name LIKE concat('%', #{warningConfig.configName}, '%')
AND cawc.status = #{warningConfig.status}
AND cceat.symbol LIKE concat('%', #{warningConfig.symbol}, '%')
